#pragma once
#include <vector>
#include <limits>

/* Return the largest sum of any contiguous subarray in the vector x.
   Implements Kadane's algorithm in O(n) time. */
int maximumSubarray(std::vector<int> const& x) {
    // Special case: empty input – return the lowest possible int value
    if (x.empty())
        return std::numeric_limits<int>::lowest();

    int max_ending_here = x[0];
    int max_so_far      = x[0];

    // Iterate through the array once, updating sums
    for (std::size_t i = 1; i < x.size(); ++i) {
        int const val = x[i];
        // Either extend the previous subarray or start a new one at x[i]
        if (max_ending_here < 0)
            max_ending_here = val;
        else
            max_ending_here += val;

        if (max_ending_here > max_so_far)
            max_so_far = max_ending_here;
    }

    return max_so_far;
}
