int edgeCount(const std::vector<int>& A, std::size_t N) {
    int count = 0;
    const int* ptr = A.data();
    const std::size_t step = N;

    #pragma omp parallel for reduction(+:count) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const int* row = ptr + i * step;
        for (std::size_t j = 0; j < N; ++j) {
            /* the expression row[j] == 1 is intrinsically a boolean;
               adding it to an integer works because true == 1. */
            count += (row[j] == 1);
        }
    }
    return count;
}
