 * output: [ 8, -11,  6,  7, -1, 0, -5]
 *
 * The implementation below is tuned for modern x86‑64 CPUs:
 *   * Parallel loop with OpenMP.
 *   * Uses bitwise test for parity instead of modulo.
 *   * Operates directly on raw pointers for maximum cache friendliness.
 */
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Parallel loop: threads get contiguous chunks (static schedule)
#ifdef _OPENMP
#pragma omp parallel for schedule(static)
#endif
    for (std::size_t i = 0; i < n; ++i) {
        const int v = x[i];
        // even test via bitwise AND
        if ((v & 1) == 0) {
            x[i] = v >> 1;          // divide by 2 (arithmetic shift preserves sign)
        } else {
            x[i] = -v;
        }
    }
}
