```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstring>

/*
   Return the length of the shortest path from source to dest
   in an undirected graph described by an N×N adjacency matrix A
   (row‑major).  The graph is guaranteed to be connected.
*/
inline int shortestPathLength(const std::vector<int> &A, size_t N,
                              int source, int dest)
{
    // Distance array, –1 indicates unvisited.
    std::vector<int> dist(N, -1);
    // Simple circular queue using a static array.
    std::vector<int> q(N);
    size_t q_head = 0, q_tail = 0;

    dist[source] = 0;
    q[q_tail++] = source;

    while (q_head != q_tail) {
        const int cur = q[q_head++];
        if (q_head == N) q_head = 0;            // wrap around

        const int cur_dist = dist[cur];
        if (cur == dest) return cur_dist;

        // Scan neighbours in order
        const size_t base = cur * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[base + i] && dist[i] == -1) {
                dist[i] = cur_dist + 1;
                q[q_tail++] = static_cast<int>(i);
                if (q_tail == N) q_tail = 0;   // wrap around
            }
        }
    }
    return std::numeric_limits<int>::max();   // unreachable (should not happen)
}
