/* Count the number of cartesian points in each quadrant. The vector `points`
   contains a list of `Point` objects. Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9}, {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
inline void countQuadrants(const std::vector<Point>& points, std::array<size_t, 4>& bins) {
    // Zero‐initialize the accumulator array
    std::array<size_t, 4> local_bins = {0, 0, 0, 0};

    #pragma omp parallel for schedule(static) reduction(+:local_bins)
    for (std::size_t i = 0; i < points.size(); ++i) {
        const auto& p = points[i];
        if (p.x >= 0.0) {
            if (p.y >= 0.0) {
                ++local_bins[0];          // Quadrant I
            } else {
                ++local_bins[3];          // Quadrant IV
            }
        } else {
            if (p.y >= 0.0) {
                ++local_bins[1];          // Quadrant II
            } else {
                ++local_bins[2];          // Quadrant III
            }
        }
    }

    // Copy the parallel results back to the output array
    bins = local_bins;
}
