18_graph_count_components:
```cpp
#pragma once
#include <vector>
#include <cstdint>

// Count connected components in an undirected graph given by a dense NxN adjacency matrix.
// N is the number of vertices, the matrix is stored row‑major in a flat vector A.
// The function keeps the original signature, but avoids recursion and uses
// a cache‑friendly depth‑first search.

int componentCount(std::vector<int> const& A, size_t N)
{
    if (N == 0) return 0;

    // Use a byte per vertex for visited flags – smaller than bool,
    // guarantees contiguous storage and no padding.
    std::vector<std::uint8_t> visited(N, 0);

    int components = 0;
    std::vector<int> stack;
    stack.reserve(N);

    for (size_t start = 0; start < N; ++start)
    {
        if (visited[start]) continue;

        // New component found
        ++components;
        stack.clear();
        stack.push_back(static_cast<int>(start));
        visited[start] = 1;

        while (!stack.empty())
        {
            int v = stack.back();
            stack.pop_back();

            // Scan row v of the adjacency matrix
            const size_t offset = v * N;
            for (size_t u = 0; u < N; ++u)
            {
                if (A[offset + u] && !visited[u])
                {
                    visited[u] = 1;
                    stack.push_back(static_cast<int>(u));
                }
            }
        }
    }

    return components;
}
```

