16_graph_largest_component:
```cpp
#pragma once
#include <vector>
#include <stack>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Return the number of vertices in the largest component of the graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major. */
int largestComponent(const std::vector<int> &A, size_t N)
{
    // visited is shared between threads but each component is processed once.
    std::vector<bool> visited(N, false);
    int global_max = 0;

    // Parallel over all vertices; each iteration will start a new component if the vertex
    // has not been visited yet.
#pragma omp parallel for schedule(static, 64)
    for (int start = 0; start < (int)N; ++start) {
        if (visited[start]) continue;

        std::stack<int> stk;
        int local_count = 0;

        // Check if we still need to process this component.
        // Use atomic compare-and-swap to avoid duplicate processing.
        bool first = false;
#pragma omp critical
        {
            if (!visited[start]) {
                visited[start] = true;
                first = true;
            }
        }
        if (!first) continue;          // another thread already started this component

        stk.push(start);
        while (!stk.empty()) {
            int v = stk.top();
            stk.pop();
            ++local_count;

            const int *row = A.data() + v * N;
            for (int u = 0; u < (int)N; ++u) {
                if (row[u] && !visited[u]) {
                    // try to claim the vertex
                    bool need_to_push = false;
#pragma omp critical
                    {
                        if (!visited[u]) {
                            visited[u] = true;
                            need_to_push = true;
                        }
                    }
                    if (need_to_push) stk.push(u);
                }
            }
        }

#pragma omp critical
        {
            if (local_count > global_max) global_max = local_count;
        }
    }

    return global_max;
}
