#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <omp.h>

/*
 * Count the number of pixels in image with each grayscale intensity.
 * The vector `image` is a grayscale image with values 0‑255.
 * Store the results in `bins`.
 *
 * Example:
 *   input:  image = {2, 116, 201, 11, 92, 92, 201, 4, 2}
 *   output: [0, 0, 2, 0, 1, ...]
 *
 * This implementation keeps the exact semantics of the original
 * function while providing a significant speed‑up on multi‑core
 * machines.  It uses per‑thread private histograms that are merged
 * at the end, eliminating expensive atomic operations inside the
 * inner loop.
 */
inline void pixelCounts(const std::vector<int> &image, std::array<std::size_t, 256> &bins)
{
    // initialise histogram to zero
    bins.fill(0);

    // determine the number of threads (0 => automatic)
    const int nthreads = omp_get_max_threads();

    // per‑thread local histograms
    std::vector<std::array<std::size_t, 256>> local(nthreads);
    for (int t = 0; t < nthreads; ++t) local[t].fill(0);

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < image.size(); ++i)
    {
        int idx = image[i];
        int tid = omp_get_thread_num();
        local[tid][static_cast<std::size_t>(idx)]++;
    }

    // merge local histograms into the result
    for (int t = 0; t < nthreads; ++t)
    {
        const auto &l = local[t];
        for (size_t v = 0; v < 256; ++v)
            bins[v] += l[v];
    }
}
