// optimised_count_quartiles.hpp
#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

inline void countQuartiles(const std::vector<double>& x, std::array<std::size_t, 4>& bins)
{
    // reset output
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // each thread keeps a private four‑element counter to avoid atomics.
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> local(n_threads);
    for (int t = 0; t < n_threads; ++t) {
        local[t][0] = local[t][1] = local[t][2] = local[t][3] = 0;
    }

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t stride = x.size() / n_threads;
        const std::size_t start = tid * stride;
        const std::size_t end   = (tid == n_threads - 1) ? x.size() : start + stride;

        std::array<std::size_t, 4>& local_bins = local[tid];

        for (std::size_t i = start; i < end; ++i) {
            const double frac = x[i] - floor(x[i]);   // more correct than int cast
            if      (frac < 0.25) local_bins[0] += 1;
            else if (frac < 0.5 ) local_bins[1] += 1;
            else if (frac < 0.75) local_bins[2] += 1;
            else                  local_bins[3] += 1;
        }
    }

    // merge private counters into global result
    for (int t = 0; t < n_threads; ++t) {
        bins[0] += local[t][0];
        bins[1] += local[t][1];
        bins[2] += local[t][2];
        bins[3] += local[t][3];
    }
}
