#pragma once
#include <vector>
#include <omp.h>

struct Element {
    size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The function assumes that the indices in x and y are sorted in ascending order,
 * but does not rely on that property for correctness.
 *
 * The implementation uses OpenMP parallel loops to perform the sparse
 * axpy operation.  Each element from x and y is processed independently,
 * and an atomic addition ensures correct updates of the shared output
 * vector `z` even when multiple threads work on the same indices.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element>& x,
                       const std::vector<Element>& y,
                       std::vector<double>& z)
