struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X
   A : M × K sparse matrix (COO)
   X : K × N sparse matrix (COO)
   Y : M × N dense matrix (row‑major)
   The routine preserves the exact semantics of the reference implementation
   but exploits multi‑threading and a hash table lookup to reduce the
   quadratic scan of the two COO lists.
*/
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    /* Allocate the dense output and zero‑initialize it */
    Y.assign(M * N, 0.0);

    /* Build a hash table mapping each row index of X to the non‑zero
       elements in that row.  A dense vector of std::vector is used
       because the number of rows K is known and usually reasonably
       small compared with the number of non‑zeros.  Each bucket
       contains a list of the non‑zero elements in that row. */
    std::vector<std::vector<COOElement>> xRow(K);
    for (auto const& e : X) {
        /* Guard against potential out‑of‑range indices – the original
           reference code assumes correct input; we keep the same
           assumption but the bounds check is cheap. */
        if (e.row < K) xRow[e.row].push_back(e);
    }

    /* Parallel over the rows of A.  The schedule is static with chunk
       size tuned to balance load.  Each thread works on a disjoint
       set of rows of A, so there is no data race on Y. */
#pragma omp parallel for schedule(static, 256) nowait
    for (size_t i = 0; i < A.size(); ++i) {
        auto const& a = A[i];
        if (a.column >= K) continue;            /* ignore invalid columns */

        auto const& rowList = xRow[a.column];
        double const av = a.value;
        size_t const aRow = a.row;
        size_t const Ncol = N;

        for (auto const& x : rowList) {
            Y[aRow * Ncol + x.column] += av * x.value;
        }
    }
}
