    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < A.size(); ++i) {
        std::size_t r = A[i].row;
        std::size_t c = A[i].column;
        if (r < y.size() && c < x.size()) {
            double const term = alpha * A[i].value * xptr[c];
            #pragma omp atomic
