/* Discrete Fourier Transform (O(N²)), numerically identical to the naive
 * implementation but heavily optimised for execution speed on
 * modern x86‑64 CPUs with OpenMP.
 *
 * Input:  x – real time‑domain samples
 * Output: output – complex frequency‑domain coefficients
 */

namespace dft_optimised
{
    // Small helper: compute complex exponential once
    inline std::complex<double> complex_exp(double angle) noexcept
    {
        return std::complex<double>(std::cos(angle), -std::sin(angle));
    }

    inline void dft(const std::vector<double> &x,
                    std::vector<std::complex<double>> &output)
    {
        const std::size_t N = x.size();
        if (N == 0) { output.clear(); return; }

        // Allocate output once
        output.assign(N, std::complex<double>(0.0, 0.0));

        // Pre‑compute the base complex roots of unity w_k = exp(-2πi k / N)
        std::vector<std::complex<double>> w_k(N);
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; ++k) {
            double angle = -2.0 * M_PI * static_cast<double>(k) / static_cast<double>(N);
            w_k[k] = complex_exp(angle);
        }

        // Main DFT loop – each k is independent → perfect OpenMP parallelism
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; ++k) {
            const std::complex<double> w = w_k[k];
            std::complex<double> wk_pow(1.0, 0.0);        // w_k^0
            std::complex<double> sum(0.0, 0.0);

            for (std::size_t n = 0; n < N; ++n) {
                sum += x[n] * wk_pow;
                wk_pow *= w;                            // Next power: w_k^(n+1)
            }
            output[k] = sum;
        }
    }
}

// Re‑export the function with the original signature
inline void dft(std::vector<double> const& x,
                std::vector<std::complex<double>> &output)
{
    dft_optimised::dft(x, output);
}
