#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
   Store the results in `output`.  No boundary padding is used – a
   value outside the array is treated as zero.
   The function is fully parallelised with OpenMP and works with the
   same semantics as the reference implementation. */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output) noexcept
{
    const std::size_t N = input.size();

    /* Guard against empty input – nothing to do. */
    if (N == 0) return;

    /* Force the output vector to the correct size. */
    output.resize(N);

    /* Use raw pointers for maximum cache locality. */
    const double* in  = input.data();
          double* out = output.data();

    /* Parallelise with OpenMP; static scheduling is efficient for
       evenly sized loops. */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < N; ++i) {
        /* Interior elements: all three neighbours exist. */
        out[i] = (in[i - 1] + in[i] + in[i + 1]) / 3.0;
    }

    /* Handle the boundaries outside the parallel loop to avoid
       branch mis‑predictions inside the hot region. */
    if (N > 1) {
        /* First element – left neighbour is zero. */
        out[0] = (in[0] + in[1]) / 3.0;

        /* Last element – right neighbour is zero. */
        out[N - 1] = (in[N - 2] + in[N - 1]) / 3.0;
    } else {
        /* Single element array – average with itself. */
        out[0] = in[0] / 3.0 * 3.0;   // keeps the original value
    }
}
