#pragma once
#include <vector>
#include <algorithm>

struct Point {
   double x, y;
};

// 2‑D convex hull (Monotone chain) – O(n log n)
inline void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    auto const n = points.size();
    if (n < 3) {                     // degenerate cases – no optimisation needed
        hull = points;
        return;
    }

    // --- 1. sort points lexicographically (x, then y) --------------------
    std::vector<Point> pts = points;              // copy for sorting
    std::sort(pts.begin(), pts.end(),
        [](Point const &a, Point const &b) {
            return a.x < b.x || (a.x == b.x && a.y < b.y);
        });

    // --- 2. cross product --------------------------------------------------
    auto cross = [](Point const &a, Point const &b, Point const &c) {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // Reserve twice the input size for the temporary hull
    std::vector<Point> tmp;
    tmp.reserve(2 * n);

    // --- 3. lower hull ----------------------------------------------------
    for (auto const &p : pts) {
        while (tmp.size() >= 2 &&
               cross(tmp[tmp.size() - 2], tmp.back(), p) <= 0.0)
            tmp.pop_back();
        tmp.push_back(p);
    }

    // --- 4. upper hull ----------------------------------------------------
    for (int i = n - 2; i >= 0; --i) {          // skip last point (already added)
        auto const &p = pts[i];
        while (tmp.size() > n &&
               cross(tmp[tmp.size() - 2], tmp.back(), p) <= 0.0)
            tmp.pop_back();
        tmp.push_back(p);
    }

    // last point == first point – remove duplicate
    tmp.pop_back();

    hull = std::move(tmp);                      // transfer ownership
}
