/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points */
inline double convexHullPerimeter(std::vector<Point> const& points)
{
    if (points.size() < 3) return 0.0;

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](Point const& a, Point const& b)
    {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    auto cross = [](Point const& a, Point const& b, Point const& c)
    {
        return (b.x - a.x) * (c.y - a.y) -
               (b.y - a.y) * (c.x - a.x);
    };

    size_t n = pts.size();
    std::vector<Point> hull(2 * n);
    size_t k = 0;

    // lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], pts[i]) <= 0.0) --k;
        hull[k++] = pts[i];
    }
    // upper hull
    size_t t = k + 1;
    for (size_t i = n; i > 0; --i)
    {
        while (k >= t && cross(hull[k - 2], hull[k - 1], pts[i - 1]) <= 0.0) --k;
        hull[k++] = pts[i - 1];
    }
    hull.resize(k - 1);

    double perim = 0.0;
    for (size_t i = 0; i + 1 < hull.size(); ++i)
        perim += dist(hull[i], hull[i + 1]);

    // close the polygon
    perim += dist(hull.front(), hull.back());
    return perim;
}
