/* Multiply an MxN matrix A (row-major) by a vector x (size N).
 * Resulting vector y (size M) is overwritten.
 *
 * The function is fully optimized for speed while keeping the exact
 * observable behaviour of the original implementation.
 */
inline void gemv(const std::vector<double> &A,
                 const std::vector<double> &x,
                 std::vector<double>        &y,
                 std::size_t M,
                 std::size_t N) noexcept
{
    // Work with raw pointers for maximum performance.
    const double *a = A.data();
    const double *vx = x.data();
    double       *vy = y.data();

    // Parallelisation over rows.  Static scheduling gives best
    // cache utilisation on modern CPUs.
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        const double *row = a + i * N;
        std::size_t j = 0;

        // Unroll the inner loop by 4 to reduce loop overhead
        // and enable vectorisation.  This pattern works
        // for any N ≥ 4; the leftover tail is handled normally.
        for (; j + 3 < N; j += 4) {
            sum += row[j]   * vx[j];
            sum += row[j+1] * vx[j+1];
            sum += row[j+2] * vx[j+2];
            sum += row[j+3] * vx[j+3];
        }
        // Tail loop for remaining elements
        for (; j < N; ++j) {
            sum += row[j] * vx[j];
        }
        vy[i] = sum;
    }
