#include <omp.h>

/* Set every cell's value to 1 if it has exactly one neighbour that's a 1.
   Neighbours are the immediately adjacent cells in the four cardinal directions.
   input and output are N×N grids laid out in row‑major order. */
template <typename T>
inline constexpr bool is_one(T v) noexcept { return v == static_cast<T>(1); }

inline void cellsXOR(const std::vector<int>& input, std::vector<int>& output, std::size_t N) {
    // Parallelise over rows; each thread will work on a distinct set of rows.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t base      = i * N;
        const std::size_t prev_base = (i > 0)     ? (i - 1) * N : SIZE_MAX; // unused when i==0
        const std::size_t next_base = (i + 1 < N) ? (i + 1) * N : SIZE_MAX; // unused when i==N-1

        for (std::size_t j = 0; j < N; ++j) {
            std::size_t idx = base + j;
            int cnt = 0;

            // Up
            if (i > 0 && is_one(input[prev_base + j])) ++cnt;
            // Down
            if (i + 1 < N && is_one(input[next_base + j])) ++cnt;
            // Left
            if (j > 0 && is_one(input[idx - 1])) ++cnt;
            // Right
            if (j + 1 < N && is_one(input[idx + 1])) ++cnt;

            output[idx] = (cnt == 1) ? 1 : 0;
        }
    }
}
