   Complexity : O(n log n)
*/
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    // Work on a copy so we can sort freely
    std::vector<Point> sorted = points;
    std::sort(sorted.begin(), sorted.end(),
              [](Point const& a, Point const& b) { return a.x < b.x; });

    std::vector<Point> active;   // points currently in the band, sorted by y
    active.reserve(n);

    double bestSq = std::numeric_limits<double>::infinity();
    size_t left = 0;

    for (size_t i = 0; i < n; ++i) {
        Point const& current = sorted[i];

        // Remove points whose x-distance exceeds best
        while (left < i) {
            double dx = current.x - sorted[left].x;
            if (dx*dx > bestSq) {
                // erase from active (maintain sorted by y)
                auto it = std::remove_if(active.begin(), active.end(),
                                         [&](Point const& p){ return p.x == sorted[left].x && p.y == sorted[left].y; });
                active.erase(it, active.end());
                ++left;
            } else break;
        }

        // Candidate points: those within sqrt(bestSq) in y
        double limit = std::sqrt(bestSq);
        auto itlow = std::lower_bound(active.begin(), active.end(), current,
                                     [](Point const& a, Point const& b){ return a.y < b.y; });
        for (auto it = itlow; it != active.end() && (*it).y - current.y <= limit; ++it) {
            double d2 = dist2(current, *it);
            if (d2 < bestSq) {
                bestSq = d2;
                limit = std::sqrt(bestSq);
            }
        }

        // Insert current into active (kept sorted by y)
        auto itins = std::lower_bound(active.begin(), active.end(), current,
                                     [](Point const& a, Point const& b){ return a.y < b.y; });
        active.insert(itins, current);
    }

    return std::sqrt(bestSq);
}
