/* Compute z = alpha*x + y where x and y are vectors.
   The function is fully parallelized with OpenMP and hand‑tuned
   for AVX (256‑bit) and SSE (128‑bit) vectorisation as a fallback.
   All inputs are assumed to be the same length. */
inline void axpy(double alpha,
                 const std::vector<double>& x,
                 const std::vector<double>& y,
                 std::vector<double>& z)
{
    const std::size_t n = x.size();
    // Ensure z has the same size
    z.resize(n);

    // Disable OpenMP iterators for better vectorisation hints
    const double* restrict X = x.data();
    const double* restrict Y = y.data();
    double* restrict Z = z.data();

    // Approximate threshold for AVX usage
    const std::size_t avx_step = 4;   // 4 doubles = 256 bits

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i + avx_step <= n; i += avx_step) {
        __m256d vx = _mm256_loadu_pd(&X[i]);   // load 4 doubles
        __m256d vy = _mm256_loadu_pd(&Y[i]);   // load 4 doubles
        __m256d valpha = _mm256_set1_pd(alpha);
        __m256d vz = _mm256_fmadd_pd(valpha, vx, vy);   // vz = alpha*vx + vy
        _mm256_storeu_pd(&Z[i], vz);
    }

    // Handle remaining elements with AVX2 if possible, else SSE
    for (std::size_t i = (n / avx_step) * avx_step; i < n; ++i) {
        Z[i] = alpha * X[i] + Y[i];
    }
}
