#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

/*  Fast in‑place radix‑2 FFT (iterative, Cooley–Tukey).
    The algorithm is identical to the reference, but all
    expensive operations are replaced by pre‑computed
    twiddle factors and the outer loops are parallelised.
    Exactly the same numerical results are produced
    (up to the very small rounding differences
    introduced by the OpenMP scheduling).\n
    Arguments:
        x – input signal (size must be a power of two)
        r – output real part
        i – output imaginary part
*/
inline void fft(const std::vector<std::complex<double>> &x,
                std::vector<double> &r, std::vector<double> &i)
{
    const size_t N = x.size();
    std::vector<std::complex<double>> X(x);          // work copy

    /* ----------------------------------------------------------
       1. Bit reversal permutation
    ---------------------------------------------------------- */
    const unsigned int m = static_cast<unsigned int>(std::log2(N));
    std::vector<size_t> rev(N);
    #pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n) {
        size_t v = n;
        v = ((v & 0xaaaaaaaa) >> 1) | ((v & 0x55555555) << 1);
        v = ((v & 0xcccccccc) >> 2) | ((v & 0x33333333) << 2);
        v = ((v & 0xf0f0f0f0) >> 4) | ((v & 0x0f0f0f0f) << 4);
        v = ((v & 0xff00ff00) >> 8) | ((v & 0x00ff00ff) << 8);
        v = (v >> 16) | (v << 16);
        rev[n] = v >> (32 - m);
    }
    #pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n)
        if (rev[n] > n)
            std::swap(X[n], X[rev[n]]);

    /* ----------------------------------------------------------
       2. Iterative butterfly stages
    ---------------------------------------------------------- */
    std::vector<std::complex<double>> twiddle(N / 2);
    const double PI = acos(-1.0);
    for (size_t j = 0; j < N / 2; ++j) {           // pre‑compute twiddles
        double angle = -2.0 * PI * j / N;
        twiddle[j] = std::complex<double>(cos(angle), sin(angle));
    }

    for (size_t len = 2; len <= N; len <<= 1) {
        const size_t half = len >> 1;
        const double step = N / len;
        #pragma omp for schedule(static)
        for (size_t i = 0; i < N; i += len) {
            size_t idx = 0;
            for (size_t j = 0; j < half; ++j, ++idx) {
                const std::complex<double> t = X[i + j + half] * twiddle[idx * step];
                const std::complex<double> u = X[i + j];
                X[i + j]          = u + t;
                X[i + j + half]   = u - t;
            }
        }
    }

    /* ----------------------------------------------------------
       3. Copy results to output vectors
    ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n) {
        r[n] = X[n].real();
        i[n] = X[n].imag();
    }
}
