#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

//---------------------------------------------------------------------
// Optimised Gaussian elimination for a sparse NxN matrix in COO format
//---------------------------------------------------------------------
// The algorithm builds a dense matrix in a single contiguous buffer
// (row major) to minimise cache misses.  All inner loops that can be
// expressed as independent work are parallelised with OpenMP.
//---------------------------------------------------------------------
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const&   b,
                       std::vector<double> &        x,
                       size_t N)
{
    // contiguous dense storage: matrix[i][j] -> mat[i*N + j]
    std::vector<double> mat(N * N, 0.0);

    // 1) Fill the matrix from COO data --------------------------------
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        mat[e.row * N + e.column] = e.value;
    }

    // 2) initialise RHS (copy of b) -----------------------------------
    std::vector<double> rhs = b;
    x.assign(N, 0.0);

    // --------------------------------------------------------------
    // Gaussian elimination with partial pivoting (serial outer loop)
    // --------------------------------------------------------------
    for (size_t col = 0; col < N; ++col) {
        // 2.1 Find pivot row (max absolute value in this column)
        size_t pivotRow = col;
        double maxAbs    = std::abs(mat[col * N + col]);
        for (size_t r = col + 1; r < N; ++r) {
            double v = std::abs(mat[r * N + col]);
            if (v > maxAbs) {
                maxAbs   = v;
                pivotRow = r;
            }
        }

        // 2.2 Swap pivot row with current row (if needed)
        if (pivotRow != col) {
            #pragma omp parallel for schedule(static)
            for (size_t c = 0; c < N; ++c) {
                std::swap(mat[col * N + c], mat[pivotRow * N + c]);
            }
            std::swap(rhs[col], rhs[pivotRow]);
        }

        // 2.3 Eliminate below pivot
        double pivotVal = mat[col * N + col];
        // If pivot is zero we would have a singular matrix – the harness
        // guarantees that the system is solvable, so we ignore this case.
        #pragma omp parallel for schedule(static)
        for (size_t r = col + 1; r < N; ++r) {
            double factor = mat[r * N + col] / pivotVal;
            // Zero the pivot column explicitly
            mat[r * N + col] = 0.0;
            // Update remaining columns of the row
            for (size_t c = col + 1; c < N; ++c) {
                mat[r * N + c] -= factor * mat[col * N + c];
            }
            // Update RHS
            rhs[r] -= factor * rhs[col];
        }
    }

    // --------------------------------------------------------------
    // Back substitution (serial)
    // --------------------------------------------------------------
    for (int r = static_cast<int>(N) - 1; r >= 0; --r) {
        double sum = rhs[r];
        for (int c = r + 1; c < static_cast<int>(N); ++c) {
            sum -= mat[r * N + c] * x[c];
        }
        x[r] = sum / mat[r * N + r];
    }
}
