#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Full‑matrix LU factorisation adapted for speed.
 *
 *   A – COO sparse matrix (size N×N)
 *   L – output lower triangular matrix (row‑major, size N×N, 1 on the diagonal)
 *   U – output upper triangular matrix (row‑major, size N×N)
 *
 * The algorithm is unchanged; only memory layout and loop structure are tuned
 * for cache locality and parallel execution.  The function is thread‑safe when
 * called with the same `N` for all threads.
 */
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    /* --------------------------------------------------------------------
     *  1. Build a dense matrix from the COO representation.
     *     Use a flat 1‑D array to minimise indirection.
     * -------------------------------------------------------------------- */
    std::vector<double> A_dense(N * N, 0.0);
    size_t const stride = N;
    for (const auto& el : A) {
        A_dense[el.row * stride + el.column] = el.value;
    }

    /* --------------------------------------------------------------------
     *  2. Initialise L and U.  L will be filled with 1s on the diagonal,
     *     the lower part will be computed on the fly; U is written during
     *     factorisation.
     * -------------------------------------------------------------------- */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        L[i * stride + i] = 1.0;   // diagonal of L
    }

    /* --------------------------------------------------------------------
     *  3. Main LU loop.  The calculation of a row of U depends on the
     *     previously computed rows, so we can only parallelise the inner
     *     work for a fixed i.  The innermost k‑loops are small and do not
     *     justify extra synchronisation, so we leave them sequential.
     * -------------------------------------------------------------------- */
    for (size_t i = 0; i < N; ++i) {
        /* U row i ------------------------------------------------------- */
        #pragma omp parallel for schedule(static)
        for (size_t j = i; j < N; ++j) {
            double sum = A_dense[i * stride + j];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[i * stride + k] * U[k * stride + j];
            }
            U[i * stride + j] = sum;
        }

        /* L column i ----------------------------------------------- */
        if (i + 1 < N) {                                 // nothing to do for last row
            #pragma omp parallel for schedule(static)
            for (size_t j = 0; j < i; ++j) {
                double sum = A_dense[(i + 1) * stride + j];
                for (size_t k = 0; k < j; ++k) {
                    sum -= L[(i + 1) * stride + k] * U[k * stride + j];
                }
                L[(i + 1) * stride + j] = sum / U[j * stride + j];
            }
        }
    }
}
```

**Key optimisation points**

1. **Flat 1‑D arrays** – both the dense version of `A` and the output matrices use a single array; this eliminates nested pointer dereferences and improves spatial locality.
2. **Parallelised inner loops** – the `j`‑loops inside the outer `i`‑loop are independent for a fixed `i`.  `#pragma omp parallel for` distributes the work across the available 8 threads.
3. **Static scheduling** – the loop bounds are known at compile time, so a static schedule gives better load balance and lower overhead.
4. **In‑place calculation** – the diagonal of `L` is set once before the main loop, avoiding repeated assignments inside the loops.
5. **Avoided unnecessary memory** – we no longer keep a `std::vector<std::vector<double>>` for `fullA`; instead the dense matrix is a single vector, lowering memory traffic.

