// Find the first even element in a vector, return its index or vec.size() if none.
inline size_t findFirstEven(const std::vector<int>& v) {
    const std::size_t n = v.size();
    const int* data = v.data();

    // Unroll by 8 to reduce loop overhead and benefit from SIMD where possible
    std::size_t i = 0;
    const std::size_t unroll = 8;
    const std::size_t limit = n & ~(unroll - 1);

    for (; i < limit; i += unroll) {
        if (data[i]     % 2 == 0) return i;
        if (data[i + 1] % 2 == 0) return i + 1;
        if (data[i + 2] % 2 == 0) return i + 2;
        if (data[i + 3] % 2 == 0) return i + 3;
        if (data[i + 4] % 2 == 0) return i + 4;
        if (data[i + 5] % 2 == 0) return i + 5;
        if (data[i + 6] % 2 == 0) return i + 6;
        if (data[i + 7] % 2 == 0) return i + 7;
    }

    for (; i < n; ++i) {
        if (data[i] % 2 == 0) return i;
    }
    return n;
}
