```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

/*
 * Solve Ax = b for x where A is an N×N matrix in row‑major order.
 * The routine preserves the exact semantics of the reference implementation:
 *   * it stops immediately if a zero pivot is encountered (undefined result)
 *   * all intermediate results are computed in double precision
 *   * the output vector `x` is overwritten with the solution.
 *
 * Performance improvements:
 *   · 1) Inlined loops with pointer arithmetic for cache friendliness.
 *   · 2) Parallelisation of the elimination step using OpenMP.
 *   · 3) Small manual SIMD (using compiler auto‑vectorisation hints).
 *   · 4) Avoiding bounds checks and redundant calculations.
 */
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              size_t N)
{
    // Work copies – required to keep the original vectors unchanged.
    std::vector<double> Acopy(A);
    std::vector<double> bcopy(b);

    // Forward elimination – parallelise the inner row updates.
    for (size_t i = 0; i + 1 < N; ++i) {
        double pivot = Acopy[i * N + i];
        if (pivot == 0.0) return;          // preserve original behaviour

        const double invPivot = 1.0 / pivot;

        // Broadcast the current pivot row pointers
        double const *rowPtr = Acopy.data() + i * N;
        double *rowBelowPtr = Acopy.data() + (i + 1) * N;
        double *bBelowPtr   = bcopy.data() + i + 1;
        double  bi          = bcopy[i];

        // Parallelise over all rows below the pivot
        #pragma omp parallel for schedule(static)
        for (ptrdiff_t j = static_cast<ptrdiff_t>(i + 1); j < static_cast<ptrdiff_t>(N); ++j) {
            double *curRow = Acopy.data() + j * N;
            double factor = curRow[i] * invPivot;          // factor = A[j,i]/pivot
            // Subtract factor * pivotRow from the current row
            for (size_t k = i; k < N; ++k) {
                curRow[k] -= factor * rowPtr[k];
            }
            bcopy[j] -= factor * bi;
        }
    }

    // Back substitution – must be performed serially
    for (int i = int(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double const *row = Acopy.data() + i * N;
        for (size_t j = i + 1; j < N; ++j) {
            sum += row[j] * x[j];
        }
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
