#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Simulate one generation of Game of Life on `input`.  
 * Store the results in `output`.  
 * Both `input` and `output` are NxN grids stored in row‑major order.  
 * The result is computed exactly as in the reference implementation, but
 * the function is heavily optimised: 
 *   * OpenMP parallelisation over all cells.  
 *   * All index calculations are performed with integers, avoiding
 *     repeated multiplications where possible.  
 *   * Boundary checks are evaluated only once per neighbour.  
 *   * The code uses int for indices and sums, as the original logic
 *     only ever requires values 0 or 1 and a sum in the range [0,8].  
 *   * The compiler can apply aggressive optimisation thanks to the
 *     plain “int” and pointer arithmetic.  
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       std::size_t N) noexcept
{
    // ptr to underlying data for faster access
    const int* in = input.data();
    int* out = output.data();

    // Parallelise the outer loop.  The inner loop
    // is collapsed so that work is evenly distributed.
#pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t base = i * N;
        std::size_t prev = (i == 0)     ? 0 : (i - 1) * N;
        std::size_t next = (i == N-1)   ? 0 : (i + 1) * N;
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;

            // vertical neighbours
            if (i > 0)     sum += in[prev + j];
            if (i < N-1)   sum += in[next + j];

            // horizontal neighbours
            if (j > 0)     sum += in[base + j - 1];
            if (j < N-1)   sum += in[base + j + 1];

            // diagonal neighbours
            if (i > 0 && j > 0)       sum += in[prev + j - 1];
            if (i > 0 && j < N-1)     sum += in[prev + j + 1];
            if (i < N-1 && j > 0)     sum += in[next + j - 1];
            if (i < N-1 && j < N-1)   sum += in[next + j + 1];

            // current cell state
            int cur = in[base + j];

            // classic Game of Life rules
            if (cur == 1) {
                out[base + j] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                out[base + j] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
