inline void bit_reverse(std::vector<std::complex<double>>& data) {
    const std::size_t N = data.size();
    const unsigned int lgN = static_cast<unsigned int>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        unsigned int j = i;
        j = ((j & 0x55555555U) << 1) | ((j & 0xaaaaaaaaU) >> 1);
        j = ((j & 0x33333333U) << 2) | ((j & 0xccccccccU) >> 2);
        j = ((j & 0x0f0f0f0fU) << 4) | ((j & 0xf0f0f0f0U) >> 4);
        j = ((j & 0x00ff00ffU) << 8) | ((j & 0xff00ff00U) >> 8);
        j = ((j & 0x0000ffffU) <<16) | ((j & 0xffff0000U) >>16);
        j >>= (32 - lgN);
        if (j > i) std::swap(data[i], data[j]);
    }
}

// Use the classic iterative radix‑2 Cooley‑Tukey, unrolled inner loop.
inline void fft_radix2(std::vector<std::complex<double>>& data) {
    const std::size_t N = data.size();
    const unsigned int levels = static_cast<unsigned int>(std::log2(N));

    // Pre‑compute twiddle factors for each stage.
    std::vector<std::complex<double>> twiddles(N/2);
    for (std::size_t i = 0; i < N/2; ++i) {
        double angle = -2.0 * M_PI * i / static_cast<double>(N);
        twiddles[i] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    for (unsigned int stage = 1; stage <= levels; ++stage) {
        const std::size_t m = 1ULL << stage;          // FFT size of this stage
        const std::size_t half = m >> 1;
        const std::size_t step = N / m;               // twiddle step

        for (std::size_t k = 0; k < half; ++k) {
            const std::complex<double> w = twiddles[k * step];
#pragma omp parallel for schedule(static)
            for (std::size_t j = k; j < N; j += m) {
                std::size_t l = j + half;
                const std::complex<double> t = w * data[l];
                data[l] = data[j] - t;
                data[j] += t;
            }
        }
    }
}

} // namespace fft_detail

// -----------------------------------------------------------

inline void fft_helper(std::vector<std::complex<double>>& x)
{
    // 1. Bit‑reverse permutation
    fft_detail::bit_reverse(x);
    // 2. FFT in place
    fft_detail::fft_radix2(x);
}

// Inverse FFT (linear‑time complex conjugate trick)
inline void ifft(std::vector<std::complex<double>>& x)
{
    // conjugate, forward FFT, conjugate again, and scale
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });
    fft_helper(x);
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });
    const double invN = 1.0 / static_cast<double>(x.size());
#pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
