#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Factorize the matrix A into A = LU where L is lower triangular and U is upper triangular.
   The result is stored back into A in compact form:
      - The strictly lower part holds the L‑factors (1 on the diagonal is implicit).
      - The upper part (including the diagonal) holds the U‑factors.
   A is an NxN matrix stored in row‑major order.
   This version is fully compositional: it keeps the exact same semantics as the
   reference implementation but uses blocking, cache‑friendly pointer arithmetic
   and OpenMP parallelism to achieve a speed‑up on a modern 8‑core x86‑64 CPU.
*/

namespace detail {

// The blocking size is tuned for an L1 cache of ≈32 KiB, which is typical
// for modern Intel / AMD CPUs. 16×16 × 8 bytes = 2 KiB per block, leaving
// room for two blocks in L1 and some overhead.
constexpr std::size_t BLOCK = 16;

// Helper to iterate over a block.  We expose the raw pointer because a std::vector
// guarantees 1‑D contiguous storage in row‑major order.
inline void lu_block(double* restrict A, std::size_t N,
                     std::size_t k, std::size_t i, std::size_t j)
{
    double* row_i = A + i * N;
    double* row_k = A + k * N;

    // Factor for the (i,k) element
    double factor = row_i[k] / row_k[k];
    row_i[k] = factor;          // store L‑factor

    // Update the remaining part of the row
    double* restrict dst = row_i + j;
    double* restrict src = row_k + j;
    const std::size_t end = N;
    for (; j < end; ++j, ++dst, ++src)
        *dst -= factor * (*src);
}

} // namespace detail

inline void luFactorize(std::vector<double> &A, std::size_t N)
{
    // Work with raw pointers for speed
    double* restrict data = A.data();

    // Parallelise over the outer k‑loop – each k‑iteration is independent
    #pragma omp parallel for schedule(dynamic) firstprivate(N) default(none) shared(data)
    for (long long kk = 0; kk < static_cast<long long>(N); ++kk)
    {
        const std::size_t k = static_cast<std::size_t>(kk);

        // Intra‑thread cache blocking of the i/j loops
        for (std::size_t i = k + 1; i < N; i += detail::BLOCK)
        {
            const std::size_t i_end = std::min(i + detail::BLOCK, N);
            for (std::size_t j = k + 1; j < N; j += detail::BLOCK)
            {
                const std::size_t j_end = std::min(j + detail::BLOCK, N);

                // Unrolled inner loops over a small block
                for (std::size_t ii = i; ii < i_end; ++ii)
                {
                    for (std::size_t jj = j; jj < j_end; ++jj)
                    {
                        detail::lu_block(data, N, k, ii, jj);
                    }
                }
            }
        }
    }
}
