#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

constexpr double PI = 3.141592653589793238462643383279502884L;

void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N < 2) return;            // nothing to do

    // ---------- bit‑reversal ----------
    std::size_t logN = 0, tmp = N;
    while (tmp >>= 1) ++logN;     // N is guaranteed to be a power of two

    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        // reverse bits over logN bits
        j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((j & 0x5555555555555555ULL) << 1);
        j = ((j & 0xccccccccccccccccULL) >> 2) | ((j & 0x3333333333333333ULL) << 2);
        j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
        j = ((j & 0xff00ff00ff00ff00ULL) >> 8) | ((j & 0x00ff00ff00ff00ffULL) << 8);
        j = ((j & 0xffff0000ffff0000ULL) >> 16) | ((j & 0x0000ffff0000ffffULL) << 16);
        j >>= (64 - logN);
        if (j > i) std::swap(x[i], x[j]);
    }

    // ---------- in‑place radix‑2 Cooley–Tukey ----------
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1ULL << s;         // 2,4,8,...
        const std::size_t half = m >> 1;         // m/2
        const double theta = -2.0 * PI / static_cast<double>(m);
        const std::complex<double> w_m = std::exp(std::complex<double>(0, theta));

        // Parallelise over the outermost blocks
#pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < N; j += m) {
            std::complex<double> w = 1.0;
            for (std::size_t k = 0; k < half; ++k) {
                std::complex<double> t = w * x[j + k + half];
                std::complex<double> u = x[j + k];
                x[j + k]     = u + t;
                x[j + k + half] = u - t;
                w *= w_m;
            }
        }
    }

    // ---------- conjugate ----------
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
