#pragma once
#include <execution>
#include <numeric>
#include <vector>
#include <utility>

/*
 * Compute the rank of each element in `x`.  
 * For equal values the original order is preserved (stable ranking).
 *
 * Example:
 * input : [3.1, 2.8, 9.1, 0.4, 3.14]
 * output: [2, 1, 4, 0, 3]
 *
 * The implementation builds a vector of (value,index) pairs,
 * performs an in‑place stable sort using the parallel execution 
 * policy provided by GCC (C++17), and finally writes the ranks.
 */
inline void ranks(const std::vector<float> &x, std::vector<size_t> &ranks_) {
    // Resize output if needed
    if (ranks_.size() != x.size()) ranks_.resize(x.size());

    // Build the (value,index) pairs with a parallel iota
    std::vector<std::pair<float, size_t>> pairs(x.size());
    std::iota(std::execution::par_unseq, pairs.begin(), pairs.end(),
              [](std::size_t i) { return std::make_pair(0.0f, i); });

    // Fill the values in a parallel loop
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        pairs[i].first = x[i];
    }

    // Stable sort the pairs by their float values
    std::stable_sort(std::execution::par_unseq, pairs.begin(), pairs.end(),
                     [](const auto &a, const auto &b) { return a.first < b.first; });

    // Write the ranks
    #pragma omp parallel for schedule(static)
    for (std::size_t rank = 0; rank < pairs.size(); ++rank) {
        ranks_[pairs[rank].second] = rank;
    }
}
