#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised 5‑point 2‑D Jacobi stencil
 *  - Uses OpenMP for parallelisation (8 threads)
 *  - Eliminates bounds checks by handling borders in a separate
 *    "guarded" loop only once
 *  - Accesses the input vector via raw pointers for maximal cache use
 *  - Performs the arithmetic in a single pass, avoiding temporary
 *    per‑element memory traffic
 */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double> &output,
                     std::size_t N)
{
    const double inv5 = 0.2;                     // 1/5.0
    const double *in = input.data();
    double *out = output.data();

    /*--- Handle the four corner points ---*/
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t idx = j;                         // (0,j)
        double sum = in[idx];
        if (j < N-1) sum += in[idx+1];
        if (j > 0)   sum += in[idx-1];
        if (j < N-1) sum += in[(N+1)*j+1];          // (1,j)
        sum += 0.0;                                  // (−1,j) missing
        out[idx] = sum * inv5;

        idx = (N-1)*N + j;                           // (N-1,j)
        sum = in[idx];
        if (j < N-1) sum += in[idx+1];
        if (j > 0)   sum += in[idx-1];
        if (j < N-1) sum += in[(N-1)*N + j+1];       // (N-2,j)
        sum += 0.0;                                  // (N,j) missing
        out[idx] = sum * inv5;
    }

    /*--- Handle the remaining rows (i from 1 to N-2) ---*/
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < N; ++i) {
        const double *top    = in + (i-1)*N;
        const double *mid    = in +  i *N;
        const double *bottom = in + (i+1)*N;
              double *midout  = out +  i *N;

        // First column (j=0)
        std::size_t j = 0;
        double sum = mid[j] + mid[j+1] + top[j] + bottom[j];
        midout[j] = sum * inv5;

        // Inner columns (j=1..N-2)
        for (j = 1; j + 1 < N; ++j) {
            sum = mid[j-1] + mid[j+1] + top[j] + bottom[j] + mid[j];
            midout[j] = sum * inv5;
        }

        // Last column (j=N-1)
        j = N-1;
        sum = mid[j] + mid[j-1] + top[j] + bottom[j];
        midout[j] = sum * inv5;
    }

    /*--- Handle the top and bottom rows (i=0, N-1) ---*/
    if (N > 2) {
        // Top row (i=0) already handled corners
        std::size_t i = 0;
        const double *mid    = in + i *N;
              double *midout  = out + i *N;
        for (std::size_t j = 1; j + 1 < N; ++j) {
            double sum = mid[j-1] + mid[j+1] +
                         mid[j] + 0.0 + // top neighbor missing
                         in[(i+1)*N + j];
            midout[j] = sum * inv5;
        }

        // Bottom row (i=N-1)
        i = N-1;
        mid    = in + i *N;
        midout = out + i *N;
        for (std::size_t j = 1; j + 1 < N; ++j) {
            double sum = mid[j-1] + mid[j+1] +
                         mid[j] +
                         0.0 +        // bottom neighbor missing
                         in[(i-1)*N + j];
            midout[j] = sum * inv5;
        }
    }
}
