#pragma once
#include <vector>
#include <cmath>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
inline size_t findClosestToPi(const std::vector<double>& x)
{
    /* Guard against an empty vector – behaviour is unspecified in the
       original implementation, so we mimic it by returning 0. */
    if (x.empty())
        return 0;

    const double pi = M_PI;
    size_t   bestIdx  = 0;
    double   bestDiff = std::fabs(x[0] - pi);

    /* Parallel reduction on a pair (diff, idx).  Each thread keeps a
       local candidate and then writes to the shared result in a critical
       section.  The overhead of the critical section is negligible
       compared with the cost of the reductions for large input sizes. */
#pragma omp parallel
    {
        size_t   localIdx  = bestIdx;
        double   localDiff = bestDiff;

        /* Process all elements except the first one (handled above) */
#pragma omp for schedule(static) nowait
        for (size_t i = 1; i < x.size(); ++i)
        {
            const double d = std::fabs(x[i] - pi);
            if (d < localDiff)
            {
                localDiff = d;
                localIdx  = i;
            }
        }

#pragma omp critical
        {
            if (localDiff < bestDiff)
            {
                bestDiff = localDiff;
                bestIdx  = localIdx;
            }
        }
    }

    return bestIdx;
}
