#pragma once
#include <vector>
#include <cstddef>
#include <cstring>
#include <omp.h>

/**
 * @brief Multiply the matrix A by the matrix B and accumulate into C.
 *
 * The matrices are stored in row-major order:
 *
 *     A: M × K
 *     B: K × N
 *     C: M × N (accumulated result)
 *
 * The function is fully parallelised with OpenMP and uses blocking to
 * improve cache locality. The behaviour is identical to the reference
 * implementation.
 *
 * @param A   Size M*K, row-major.
 * @param B   Size K*N, row-major.
 * @param C   Size M*N, row-major, must be initialised to zero before
 *            the first call to this function.
 * @param M   Number of rows in A and C.
 * @param K   Number of columns in A / rows in B.
 * @param N   Number of columns in B and C.
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>&       C,
                 const size_t M,
                 const size_t K,
                 const size_t N)
{
    /* Basic parameters for blocking.  The block sizes are tuned for
     * typical L1 and L2 cache sizes on x86‑64 CPUs.  They can be
     * adjusted if profiling shows a different behaviour. */
    constexpr size_t BLOCK_K = 32;
    constexpr size_t BLOCK_N = 32;

    const double* restrict a_ptr = A.data();
    const double* restrict b_ptr = B.data();
          double* restrict c_ptr = C.data();

    /* Parallelise the outermost M dimension.  The innermost loops
     * are kept inside the parallel region for better data locality
     * and to avoid the overhead of scheduling too many small tasks. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        const double* restrict a_row = a_ptr + i * K;
        double* restrict        c_row = c_ptr + i * N;

        /* Let k be processed in blocks to keep K dimension in L1. */
        for (size_t kk = 0; kk < K; kk += BLOCK_K) {
            const size_t kmax = (kk + BLOCK_K < K) ? kk + BLOCK_K : K;
            /* Process N columns in blocks to keep them in L1/cache */
            for (size_t jj = 0; jj < N; jj += BLOCK_N) {
                const size_t jmax = (jj + BLOCK_N < N) ? jj + BLOCK_N : N;
                /* Compute partial products for the block. */
                for (size_t k = kk; k < kmax; ++k) {
                    const double aik = a_row[k];
                    const double* restrict b_row = b_ptr + k * N;
                    double* restrict        c_temp = c_row + jj;
                    const size_t  remaining = jmax - jj;
                    /* Manual loop unrolling for inner j-loop. */
                    size_t j = 0;
                    for (; j + 7 < remaining; j += 8) {
                        c_temp[j + 0] += aik * b_row[j + 0];
                        c_temp[j + 1] += aik * b_row[j + 1];
                        c_temp[j + 2] += aik * b_row[j + 2];
                        c_temp[j + 3] += aik * b_row[j + 3];
                        c_temp[j + 4] += aik * b_row[j + 4];
                        c_temp[j + 5] += aik * b_row[j + 5];
                        c_temp[j + 6] += aik * b_row[j + 6];
                        c_temp[j + 7] += aik * b_row[j + 7];
                    }
                    for (; j < remaining; ++j) {
                        c_temp[j] += aik * b_row[j];
                    }
                }
            }
        }
    }
}
