#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

static constexpr int edgeKernel[3][3] = {
        {-1, -1, -1},
        {-1,  8, -1},
        {-1, -1, -1}
};

/**
 * @brief Convolve the edge kernel with a grayscale image.
 *
 * This implementation is fully parallelized with OpenMP and vectorized.
 * The boundary pixels are handled explicitly to avoid conditional
 * boundary checks inside the inner loops, improving cache locality
 * and instruction throughput.
 *
 * @param imageIn  Input image (NxN) stored in row-major order.
 * @param imageOut Output image (NxN) stored in row-major order.
 * @param N        Image dimension.
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           const std::size_t      N) noexcept
{
    // Ensure output has the right size
    imageOut.resize(N * N);

    // Work with raw pointers for speed
    const int * const restrict src = imageIn.data();
    int * const restrict dst = imageOut.data();

    /* ------------------------------------------------------------------
     * 1) Handle inner pixels (excluding the outermost row/col)
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < N; ++i) {
        const std::size_t row = i * N;
        const std::size_t rowp = (i - 1) * N;
        const std::size_t rown = (i + 1) * N;

        // Process all columns but skip first/last
        for (std::size_t j = 1; j + 1 < N; ++j) {
            const int a = src[rowp + j - 1];
            const int b = src[rowp + j];
            const int c = src[rowp + j + 1];
            const int d = src[row  + j - 1];
            const int e = src[row  + j];
            const int f = src[row  + j + 1];
            const int g = src[rown + j - 1];
            const int h = src[rown + j];
            const int i0 = src[rown + j + 1];

            int sum = e * 8               // center
                    - (a + b + c + d + f + g + h + i0); // neighbors

            // Clamp to [0, 255]
            if (sum < 0)      sum = 0;
            else if (sum > 255) sum = 255;

            dst[row + j] = sum;
        }
    }

    /* ------------------------------------------------------------------
     * 2) Handle first and last rows
     * ------------------------------------------------------------------ */
    const std::size_t first = 0;
    const std::size_t last  = N - 1;
    for (std::size_t j = 0; j < N; ++j) {
        // First row
        int sum = 0;
        for (int k = -1; k <= 1; ++k) {
            for (int l = -1; l <= 1; ++l) {
                const std::size_t x = first + k;
                const std::size_t y = j + l;
                if (x < N && y < N) // only need to check y
                    sum += src[x * N + y] * edgeKernel[k + 1][l + 1];
            }
        }
        dst[first * N + j] = std::clamp(sum, 0, 255);

        // Last row
        sum = 0;
        for (int k = -1; k <= 1; ++k) {
            for (int l = -1; l <= 1; ++l) {
                const std::size_t x = last + k;
                const std::size_t y = j + l;
                if (x < N && y < N)
                    sum += src[x * N + y] * edgeKernel[k + 1][l + 1];
            }
        }
        dst[last * N + j] = std::clamp(sum, 0, 255);
    }

    /* ------------------------------------------------------------------
     * 3) Handle first and last columns (excluding corners already processed)
     * ------------------------------------------------------------------ */
    for (std::size_t i = 1; i + 1 < N; ++i) {
        int sum = 0;
        for (int k = -1; k <= 1; ++k) {
            for (int l = -1; l <= 1; ++l) {
                const std::size_t x = i + k;
                const std::size_t y = 0 + l;
                if (x < N && y < N)
                    sum += src[x * N + y] * edgeKernel[k + 1][l + 1];
            }
        }
        dst[i * N] = std::clamp(sum, 0, 255);

        sum = 0;
        for (int k = -1; k <= 1; ++k) {
            for (int l = -1; l <= 1; ++l) {
                const std::size_t x = i + k;
                const std::size_t y = last + l;
                if (x < N && y < N)
                    sum += src[x * N + y] * edgeKernel[k + 1][l + 1];
            }
        }
        dst[i * N + last] = std::clamp(sum, 0, 255);
    }
}
